List<Aufgabe> aufgabenHeute() {
    List<Aufgabe> liste = new List<Aufgabe>();
    for (int i = 0; i < aufgaben.size(); i++) {
        Aufgabe a = aufgaben.get(i);
        if (a.heuteAusfuehrbar()) {
            liste.add(a);
        }
    }
    return liste;
}
